namespace ResumeBuilder.API.Models;
public class ApiResponse<T> { public bool Success { get; set; } public string? Message { get; set; } public T? Data { get; set; } public string[]? Errors { get; set; } public DateTime Timestamp { get; set; } = DateTime.UtcNow; public static ApiResponse<T> Ok(T data, string? message = null) => new() { Success = true, Data = data, Message = message }; public static ApiResponse<T> Created(T data, string? message = "Created.") => new() { Success = true, Data = data, Message = message }; public static ApiResponse<T> Fail(string error) => new() { Success = false, Errors = new[] { error } }; public static ApiResponse<T> Fail(IEnumerable<string> errors) => new() { Success = false, Errors = errors.ToArray() }; }
public class PagedApiResponse<T> { public bool Success { get; set; } public string? Message { get; set; } public List<T>? Items { get; set; } public int PageNumber { get; set; } public int TotalPages { get; set; } public int TotalCount { get; set; } public bool HasPreviousPage { get; set; } public bool HasNextPage { get; set; } public DateTime Timestamp { get; set; } = DateTime.UtcNow; }
